  ('rgn_red_sea', '홍해 (갈대 바다)', '수에즈만 좁은 해협. 출애굽 시 바다가 갈라진 곳.', '📍', null, 28.5, 32.95, '[[30.0, 32.4], [29.5, 32.55], [29.0, 32.75], [28.5, 32.95], [28.0, 33.1], [27.6, 33.2], [27.3, 33.2], [27.1, 33.05], [27.1, 32.85], [27.3, 32.65], [27.7, 32.5], [28.2, 32.45], [28.8, 32.42], [29.5, 32.4]]'::jsonb, 'region', null, null, 90, '{"era_exodus"}'::text[], '{}'::text[]),
