  ('rgn_idumea', '에돔', '사해 남쪽 ~ 아카바 만 사이의 산지. 에돔 산지·세일·페트라.', '📍', null, 30.32, 35.46, '[[29.5, 35.4], [29.8, 35.4], [30.1, 35.4], [30.4, 35.4], [30.65, 35.4], [30.78, 35.4], [30.85, 35.45], [30.85, 35.55], [30.85, 35.7], [30.85, 35.85], [30.85, 36.0], [30.5, 36.0], [30.1, 36.0], [29.7, 36.0], [29.5, 35.9], [29.5, 35.65]]'::jsonb, 'region', null, null, 70, '{"era_patriarch","era_exodus","era_monarchy"}'::text[], '{}'::text[]),
  ('rgn_philistia', '블레셋 평원', '지중해 동안 평원의 블레셋 5도성: 가사·아스돗·아스글론·가드·에그론.', '📍', null, 31.6, 34.65, '[[31.2, 34.3], [31.3, 34.32], [31.45, 34.4], [31.55, 34.5], [31.65, 34.55], [31.78, 34.65], [31.85, 34.78], [31.85, 34.92], [31.85, 34.95], [31.65, 34.95], [31.45, 34.95], [31.3, 34.95], [31.2, 34.95], [31.2, 34.78], [31.2, 34.55], [31.2, 34.4]]'::jsonb, 'region', null, null, 80, '{"era_judges","era_monarchy","era_nt_apostolic"}'::text[], '{}'::text[]),
  ('rgn_judea', '유대', '유다 산지 + 베냐민 + 사해 권역 + 유대 광야. 예루살렘·베들레헴·헤브론·여리고·사해. 사사 유다지파부터 신약 로마 속주까지 통합.', '📍', null, 31.55, 35.25, '[[30.9, 34.95], [31.05, 34.95], [31.2, 34.95], [31.4, 34.95], [31.55, 34.97], [31.7, 34.99], [31.82, 35.0], [31.92, 35.02], [31.95, 35.1], [31.93, 35.2], [31.95, 35.32], [31.95, 35.45], [31.95, 35.52], [31.85, 35.52], [31.7, 35.5], [31.55, 35.5], [31.4, 35.5], [31.25, 35.48], [31.1, 35.46], [30.95, 35.5], [30.9, 35.5], [30.85, 35.45], [30.88, 35.3], [30.9, 35.15], [30.9, 35.0]]'::jsonb, 'region', null, null, 100, '{"era_patriarch","era_judges","era_monarchy","era_exile_return","era_nt_public_ministry","era_nt_apostolic","era_nt_post_apostolic"}'::text[], '{}'::text[]),
  ('rgn_samaria', '사마리아', '에브라임 산지 + 므낫세 일부. 세겜·실로·벧엘·도단·사마리아 성. 사사 에브라임부터 분열왕국 북이스라엘 수도, 신약 사마리아까지 통합.', '📍', null, 32.4, 35.25, '[[31.92, 35.02], [31.95, 35.1], [31.93, 35.2], [31.95, 35.32], [31.95, 35.45], [31.95, 35.52], [32.1, 35.55], [32.25, 35.55], [32.4, 35.55], [32.5, 35.5], [32.55, 35.4], [32.58, 35.25], [32.55, 35.12], [32.5, 35.0], [32.4, 34.95], [32.25, 34.95], [32.1, 34.95], [32.0, 34.95], [31.92, 34.97]]'::jsonb, 'region', null, null, 90, '{"era_patriarch","era_judges","era_monarchy","era_nt_public_ministry","era_nt_apostolic"}'::text[], '{}'::text[]),
  ('rgn_galilee', '갈릴리·이스르엘', '갈릴리 호수 + 갈릴리 산지 + 이스르엘 평원 + 갈멜 + 헤르몬 남쪽. 가버나움·나사렛·가나·므깃도·다볼·길보아·세사라빌립보.', '📍', null, 32.95, 35.3, '[[32.5, 35.0], [32.55, 35.12], [32.58, 35.25], [32.55, 35.4], [32.5, 35.5], [32.55, 35.57], [32.65, 35.58], [32.78, 35.58], [32.85, 35.62], [32.95, 35.65], [33.1, 35.7], [33.2, 35.78], [33.3, 35.85], [33.3, 35.55], [33.25, 35.3], [33.2, 35.1], [33.2, 34.95], [33.1, 34.95], [32.95, 34.95], [32.8, 34.95], [32.65, 34.95], [32.6, 34.97]]'::jsonb, 'region', null, null, 100, '{"era_judges","era_monarchy","era_nt_public_ministry","era_nt_apostolic"}'::text[], '{}'::text[]),
  ('rgn_coastal_plain', '해안 평원 (사론)', '지중해 동안 사론 평원. 가이사랴(해변)·욥바·룻다·아리마대.', '📍', null, 32.3, 34.75, '[[31.85, 34.7], [31.95, 34.78], [32.05, 34.82], [32.15, 34.85], [32.25, 34.85], [32.35, 34.83], [32.45, 34.84], [32.55, 34.87], [32.65, 34.92], [32.65, 34.95], [32.55, 34.95], [32.4, 34.95], [32.2, 34.95], [32.0, 34.95], [31.92, 34.95], [31.85, 34.95]]'::jsonb, 'region', null, null, 80, '{"era_monarchy","era_nt_public_ministry","era_nt_apostolic"}'::text[], '{}'::text[]),
  ('rgn_moab', '모압', '사해 동편 고원. 모압 평지(가나안 입성 직전)·룻의 고향·발람.', '📍', null, 31.55, 35.72, '[[30.95, 35.55], [31.1, 35.55], [31.25, 35.55], [31.4, 35.55], [31.55, 35.55], [31.7, 35.55], [31.85, 35.55], [31.85, 35.7], [31.85, 35.85], [31.85, 35.95], [31.65, 35.95], [31.4, 35.95], [31.15, 35.95], [30.95, 35.95], [30.95, 35.85], [30.95, 35.7]]'::jsonb, 'region', null, null, 70, '{"era_exodus","era_judges","era_monarchy"}'::text[], '{}'::text[]),
  ('rgn_ammon', '암몬', '요단 동편 북부. 랍바암몬(현 암만). 입다·다윗 시대 적국.', '📍', null, 31.95, 35.93, '[[31.5, 35.95], [31.65, 35.95], [31.85, 35.95], [32.0, 35.95], [32.1, 35.95], [32.1, 36.1], [32.1, 36.3], [32.1, 36.45], [32.05, 36.55], [31.85, 36.55], [31.65, 36.5], [31.5, 36.4], [31.5, 36.2], [31.5, 36.05]]'::jsonb, 'region', null, null, 70, '{"era_judges","era_monarchy"}'::text[], '{}'::text[]),
  ('rgn_gilead', '길르앗', '요단 동편 중부. 얍복강·라못길르앗·얍베스길르앗·미스바 길르앗. 야곱 라반 추격, 입다, 엘리야의 고향.', '📍', null, 32.3, 35.85, '[[32.1, 35.55], [32.1, 35.7], [32.1, 35.85], [32.1, 36.0], [32.15, 36.15], [32.25, 36.3], [32.25, 36.1], [32.25, 35.95], [32.25, 35.85], [32.25, 35.7], [32.25, 35.6], [32.2, 35.55], [32.15, 35.55]]'::jsonb, 'region', null, null, 70, '{"era_patriarch","era_judges","era_monarchy"}'::text[], '{}'::text[]),
  ('rgn_bashan', '바산', '요단 동편 북단 고원. 바산 옥 왕·헤르몬 남쪽 평원. 골란 일대.', '📍', null, 32.95, 36.1, '[[32.85, 35.85], [32.85, 36.05], [32.85, 36.25], [32.85, 36.5], [33.0, 36.55], [33.2, 36.55], [33.4, 36.55], [33.4, 36.3], [33.4, 36.05], [33.4, 35.85], [33.3, 35.85], [33.1, 35.85], [32.95, 35.85]]'::jsonb, 'region', null, null, 60, '{"era_exodus","era_judges","era_monarchy"}'::text[], '{}'::text[]),
