  ('rgn_decapolis', '데카폴리스', '갈릴리 동남 10개 헬라 도시 연합. 거라사·가다라·스굿도볼리.', '📍', null, 32.5, 35.85, '[[32.25, 35.55], [32.4, 35.55], [32.5, 35.5], [32.55, 35.57], [32.65, 35.58], [32.78, 35.58], [32.85, 35.65], [32.85, 35.85], [32.85, 36.05], [32.85, 36.3], [32.8, 36.4], [32.65, 36.42], [32.5, 36.4], [32.35, 36.35], [32.25, 36.25], [32.25, 36.05], [32.25, 35.85], [32.25, 35.7]]'::jsonb, 'region', null, null, 60, '{"era_nt_public_ministry"}'::text[], '{}'::text[]),
  ('rgn_phoenicia', '페니키아', '지중해 동안 북부 해안. 두로·시돈·사렙다·비블로스. 엘리야의 사렙다 과부, 예수의 가나안 여인, 바울 여행.', '📍', null, 33.5, 35.4, '[[33.2, 35.1], [33.25, 35.15], [33.4, 35.2], [33.55, 35.25], [33.7, 35.3], [33.85, 35.4], [34.0, 35.5], [34.2, 35.6], [34.4, 35.7], [34.55, 35.85], [34.55, 36.05], [34.4, 36.05], [34.2, 35.95], [34.0, 35.85], [33.85, 35.78], [33.7, 35.68], [33.55, 35.58], [33.4, 35.45], [33.3, 35.3], [33.25, 35.2]]'::jsonb, 'region', null, null, 80, '{"era_monarchy","era_nt_public_ministry","era_nt_apostolic"}'::text[], '{}'::text[]),
  ('rgn_aram_damascus', '다메섹 아람', '다메섹을 수도로 한 시리아 남부 아람 왕국 + 신약 시리아 남부. 엘리사·바울 회심.', '📍', null, 33.51, 36.3, '[[33.4, 36.05], [33.4, 36.3], [33.4, 36.55], [33.4, 36.85], [33.4, 37.2], [33.4, 37.5], [33.6, 37.5], [33.85, 37.5], [34.1, 37.5], [34.35, 37.5], [34.5, 37.5], [34.5, 37.2], [34.5, 36.9], [34.5, 36.55], [34.5, 36.2], [34.5, 36.05], [34.25, 36.05], [34.0, 36.05], [33.75, 36.05], [33.55, 36.05]]'::jsonb, 'region', null, null, 90, '{"era_monarchy","era_nt_apostolic"}'::text[], '{}'::text[]),
  ('rgn_syria_north', '시리아 북부', '오론테스 강 일대. 안디옥(시리아)·셀류시아 항구. 이방 선교 베이스.', '📍', null, 36.2, 36.16, '[[36.6783, 37.5235], [36.9016, 38.1917], [36.8316, 38.5], [34.5, 38.5], [34.5, 36.3298], [34.6135, 36.433], [34.6579, 36.3839], [34.6292, 35.9763], [35.4207, 35.9024], [35.5716, 35.7645], [35.9981, 35.9569], [36.3099, 35.8109], [36.659, 36.1885], [36.8072, 36.1801], [36.9106, 36.0489], [36.5914, 35.5], [37.5, 35.5], [37.5, 37.5], [36.6783, 37.5235]]'::jsonb, 'region', null, null, 90, '{"era_nt_apostolic"}'::text[], '{}'::text[]),
  ('rgn_cyprus', '구브로', '지중해 동부 섬 (키프로스). 살라미·바보. 바울 1차 전도여행.', '📍', null, 35.05, 33.45, '[[35.171, 32.7127], [35.0878, 32.9195], [35.1731, 33.191], [35.1627, 33.3838], [35.0003, 33.4758], [35.0936, 33.8664], [35.0652, 34.0045], [34.9884, 34.0502], [34.9699, 33.6994], [34.7509, 33.4149], [34.6956, 33.1155], [34.5696, 33.0079], [34.5759, 32.9418], [34.6611, 32.8672], [34.7294, 32.449], [34.9533, 32.3172], [35.083, 32.301], [35.0498, 32.3909], [35.1558, 32.556], [35.171, 32.7127]]'::jsonb, 'region', null, null, 80, '{"era_nt_apostolic"}'::text[], '{}'::text[]),
  ('rgn_crete', '그레데', '지중해 크레타 섬. 미항·라새아. 바울 로마행 항로.', '📍', null, 35.24, 24.81, '[[35.5282, 23.9206], [35.5952, 24.166], [35.5375, 24.1978], [35.4958, 24.109], [35.4686, 24.2554], [35.386, 24.2749], [35.3595, 24.354], [35.4248, 24.7213], [35.3062, 25.4757], [35.3486, 25.7302], [35.1229, 25.7913], [35.2151, 26.1679], [35.3151, 26.3202], [35.0447, 26.2443], [35.0186, 26.1656], [34.9345, 24.7998], [35.0891, 24.7089], [35.2461, 23.8836], [35.2352, 23.6381], [35.2952, 23.5616], [35.5348, 23.5698], [35.5139, 23.6727], [35.6555, 23.7369], [35.5562, 23.7934], [35.5282, 23.9206]]'::jsonb, 'region', null, null, 70, '{"era_nt_apostolic"}'::text[], '{}'::text[]),
  ('rgn_malta', '멜리데', '지중해 중앙 섬 (몰타). 바울 표류지.', '📍', null, 35.94, 14.4, '[[35.8527, 14.5662], [35.8202, 14.5327], [35.8217, 14.4364], [35.8723, 14.3523], [35.9784, 14.3513], [35.9574, 14.4483], [35.8527, 14.5662]]'::jsonb, 'region', null, null, 70, '{"era_nt_apostolic"}'::text[], '{}'::text[]),
  ('rgn_patmos', '밧모', '에게해 동부 작은 섬. 사도 요한 유배지·요한계시록 환상의 무대.', '📍', null, 37.31, 26.55, '[[37.4, 26.5], [37.4, 26.55], [37.38, 26.62], [37.33, 26.65], [37.27, 26.65], [37.23, 26.6], [37.23, 26.53], [37.27, 26.48], [37.33, 26.46], [37.38, 26.48]]'::jsonb, 'region', null, null, 80, '{"era_nt_post_apostolic"}'::text[], '{}'::text[]),
  ('rgn_galatia', '갈라디아', '아나톨리아 중남부 (현 터키 중부). 비시디아안디옥·이고니온·루스드라·더베. 바울 1·2·3차 전도여행 통과.', '📍', null, 38.5, 31.0, '[[37.0, 30.8], [37.3, 30.85], [37.6, 30.95], [38.0, 31.1], [38.4, 31.2], [38.8, 31.4], [39.2, 31.65], [39.6, 32.0], [40.0, 32.5], [40.3, 33.1], [40.3, 33.8], [40.2, 34.3], [39.8, 34.45], [39.2, 34.5], [38.5, 34.5], [37.8, 34.4], [37.3, 34.1], [37.05, 33.6], [37.0, 33.0], [37.0, 32.2], [37.0, 31.4]]'::jsonb, 'region', null, null, 90, '{"era_nt_apostolic"}'::text[], '{}'::text[]),
  ('rgn_asia_province', '아시아', '아나톨리아 서부 + 남쪽 해안 루기아 일부 (현 터키 서부). 에베소·드로아·밀레도·골로새·라오디게아·서머나·버가모·두아디라·사데·빌라델비아·무라·바다라. 바울 2·3차 전도여행 + 계시록 일곱 교회.', '📍', null, 38.5, 27.5, '[[36.3104, 30.4836], [36.1567, 29.6891], [36.3245, 29.2236], [36.7153, 28.9696], [36.812, 28.3037], [36.6345, 28.0194], [36.7515, 28.084], [36.7122, 27.4539], [36.832, 28.0054], [37.0291, 28.2424], [36.9766, 27.263], [37.1269, 27.3002], [37.1639, 27.5351], [37.6579, 27.068], [37.7254, 27.2244], [37.9787, 27.2324], [38.2772, 26.2907], [38.3679, 26.4164], [38.6412, 26.4413], [38.3357, 26.6742], [38.452, 27.1442], [38.4817, 26.9068], [38.7096, 26.7637], [38.8869, 27.0137], [38.961, 26.8149], [39.1156, 26.8536], [39.2922, 26.6818], [39.5497, 26.8992], [39.4674, 26.1131], [39.9901, 26.1813], [40.4002, 26.7381], [40.4556, 27.2846], [40.3288, 27.728], [40.3817, 27.8485], [40.4815, 27.7318], [40.5129, 27.8749], [40.4895, 27.9896], [40.3699, 27.9626], [40.3897, 29.0071], [40.534, 28.7879], [40.7381, 29.8449], [40.9378, 29.1139], [41.221, 29.1481], [41.1596, 30.5], [36.3104, 30.4836]]'::jsonb, 'region', null, null, 100, '{"era_nt_apostolic","era_nt_post_apostolic"}'::text[], '{}'::text[]),
  ('rgn_macedonia', '마게도냐', '그리스 북부 + 발칸 서북(일루리곤 흡수). 빌립보·데살로니가·베뢰아·암비볼리. 바울 2·3차 전도여행.', '📍', null, 40.78, 23.05, '[[41.6306, 26.5], [40.9971, 26.3541], [40.7268, 26.039], [40.9947, 25.1045], [40.7478, 23.7628], [40.4186, 23.8668], [40.3278, 24.2128], [40.1477, 24.3434], [40.3297, 23.7279], [39.9656, 23.9471], [40.264, 23.4263], [39.9589, 23.6741], [39.9898, 23.3956], [40.2165, 23.312], [40.3999, 22.8965], [40.5909, 22.9223], [40.4956, 22.6295], [40.0369, 22.5922], [39.5, 23.0896], [39.5, 20.2143], [40.0436, 19.8519], [40.4071, 19.3223], [40.4054, 19.4592], [40.6638, 19.3375], [41.7875, 19.5775], [41.8691, 19.3424], [42.1726, 19.2807], [42.6479, 19.7034], [42.4762, 19.7883], [42.5473, 20.064], [42.2234, 20.4854], [41.8737, 20.5662], [41.8538, 20.6949], [42.071, 20.7781], [42.1713, 21.0598], [42.3289, 22.4221], [42.8425, 22.4668], [43.0, 22.8249], [43.0, 26.5], [41.8245, 26.5], [41.7447, 26.318], [41.6306, 26.5]]'::jsonb, 'region', null, null, 90, '{"era_nt_apostolic"}'::text[], '{}'::text[]),
  ('rgn_achaia', '아가야 (헬라)', '그리스 본토 남부 + 펠로폰네소스. 아덴·고린도·겐그레아. 바울 2·3차 전도여행.', '📍', null, 37.97, 23.72, '[[39.492, 23.1034], [39.1749, 23.3277], [39.1015, 23.1547], [39.2578, 23.1617], [39.3063, 22.9214], [39.17, 22.886], [39.0379, 23.0667], [38.8675, 22.5691], [38.275, 23.967], [37.7096, 24.0554], [38.0328, 23.5372], [37.9026, 23.0475], [37.6202, 23.1976], [37.4639, 23.4906], [37.3338, 23.1615], [37.5421, 22.7254], [36.4481, 23.1602], [36.7939, 22.7172], [36.7797, 22.6084], [36.4469, 22.4895], [37.029, 22.0805], [36.9901, 21.9556], [36.7373, 21.8924], [36.8632, 21.7381], [37.081, 21.5829], [37.3872, 21.6789], [37.8916, 21.1247], [38.1967, 21.4037], [38.1751, 21.6584], [38.3281, 21.8247], [37.9676, 22.8464], [38.1337, 23.1835], [38.4385, 22.4217], [38.3214, 21.4726], [38.4873, 21.3311], [38.3456, 21.1826], [38.8744, 20.7686], [38.8963, 21.1116], [39.03, 21.1184], [39.0352, 20.7134], [39.5, 20.2143], [39.492, 23.1034]]'::jsonb, 'region', null, null, 90, '{"era_nt_apostolic"}'::text[], '{}'::text[]),
  ('rgn_italy', '이탈리아', '로마 제국 수도. 로마·보디올·아피오 광장·삼관. 바울 마지막 사역지.', '📍', null, 41.9, 12.5, '[[45.9258, 7.0211], [45.9218, 7.7879], [46.446, 8.4226], [46.2459, 8.4584], [45.8457, 9.0237], [46.4956, 9.3044], [46.3062, 9.5287], [46.3618, 9.9393], [46.228, 10.0806], [46.5999, 10.087], [46.55, 10.4307], [46.8649, 10.4528], [46.777, 10.9933], [46.9757, 11.2444], [47.0821, 12.1694], [46.7026, 12.3883], [46.5203, 13.7], [46.2616, 13.3782], [46.1771, 13.6325], [45.9871, 13.4877], [45.6148, 13.8747], [45.7714, 13.2063], [45.446, 12.2743], [45.2415, 12.2257], [44.968, 12.5234], [44.7225, 12.2483], [44.2239, 12.3963], [43.5713, 13.5642], [42.6896, 14.0104], [42.2443, 14.5407], [41.934, 15.1687], [41.8962, 16.1646], [41.5121, 15.9005], [40.6552, 17.955], [40.221, 18.4606], [39.9036, 18.3935], [39.937, 18.0779], [40.2802, 17.865], [40.4581, 16.9282], [39.7476, 16.5219], [39.3806, 17.1146], [38.9981, 17.1746], [38.8001, 16.6167], [38.4091, 16.5456], [37.9418, 16.0568], [37.9391, 15.7245], [38.1754, 15.6431], [38.9411, 16.21], [39.9902, 15.6928], [40.239, 14.9509], [40.6684, 14.7657], [40.5988, 14.3399], [40.7287, 14.4605], [40.8123, 14.0443], [41.2356, 13.7334], [41.2438, 13.0887], [42.2875, 11.6373], [42.4166, 11.1032], [42.5352, 11.1678], [42.9675, 10.5148], [43.8521, 10.2458], [44.02, 10.0477], [44.4223, 8.7658], [43.8768, 8.005], [43.7671, 7.4932], [44.1648, 7.6372], [44.3357, 6.9002], [44.8273, 6.9927], [45.0682, 6.6348], [45.3817, 7.1464], [45.7409, 6.7909], [45.9258, 7.0211]]'::jsonb, 'region', null, null, 90, '{"era_nt_apostolic","era_nt_post_apostolic"}'::text[], '{}'::text[]),
  ('rgn_armageddon', '아마겟돈', '므깃도 인근 이스르엘 평원. 요한계시록 16장의 종말 전쟁 무대.', '📍', null, 32.58, 35.18, '[[32.7, 35.0], [32.7, 35.4], [32.5, 35.4], [32.5, 35.0]]'::jsonb, 'region', null, null, 70, '{"era_nt_consummation"}'::text[], '{}'::text[]),
  ('rgn_heavenly_throne', '하늘 보좌', '요한계시록 4-5장의 하늘 환상. 비지리적 — 지도 모서리 카드로 표현.', '📍', null, null, null, '[]'::jsonb, 'region', null, null, 50, '{"era_nt_consummation"}'::text[], '{}'::text[]),
  ('rgn_new_jerusalem', '새 예루살렘', '요한계시록 21-22장의 종말 환상. 비지리적 — 지도 모서리 카드로 표현.', '📍', null, null, null, '[]'::jsonb, 'region', null, null, 50, '{"era_nt_consummation"}'::text[], '{}'::text[])
insert into landmarks (code, name, description, emoji, category, lat, lng, polygon, kind, parent_landmark_id, alias_group_id, display_priority, era_codes, related_event_codes) values
  ('lm_exi_babylon', '바벨론', '유다 왕국 멸망 후 포로로 끌려간 제국 수도 (왕하 25장). 다니엘 활동 무대.', '🗼', null, 32.5421, 44.4209, null, 'city', (select id from landmarks where code = 'rgn_mesopotamia'), null, 50, '{"era_exile_return"}'::text[], '{}'::text[]),
  ('lm_exi_chebar', '그발 강가(추정)', '에스겔이 환상을 본 강가 (겔 1장). 바벨론 포로 정착지.', '👁️', null, 32.65, 44.6, null, 'river', (select id from landmarks where code = 'rgn_mesopotamia'), null, 50, '{"era_exile_return"}'::text[], '{}'::text[]),
  ('lm_exi_jerusalem', '바벨론 → 예루살렘(전승)', '포로 귀환 후 재건된 성 (스 1장, 느 1-6장). 성전·성벽 복원.', '🏛️', null, 31.778, 35.2354, null, 'city', (select id from landmarks where code = 'rgn_judea'), null, 50, '{"era_exile_return"}'::text[], '{}'::text[]),
  ('lm_exi_susa', '수산 궁(페르시아)', '페르시아 제국 도시. 에스더 사건의 무대 (에 1장), 다니엘 환상 (단 8장).', '👑', null, 32.1881, 48.2581, null, 'city', (select id from landmarks where code = 'rgn_persia'), null, 50, '{"era_exile_return"}'::text[], '{}'::text[]),
  ('lm_exo_edom_road', '광야(에돔 길, 전승)', '에돔 왕에게 통행을 거절당해 이스라엘이 우회한 길 (민 20장).', '🏜️', null, 30.3, 35.3, null, 'wilderness', (select id from landmarks where code = 'rgn_negev'), null, 50, '{"era_exodus"}'::text[], '{}'::text[]),
  ('lm_exo_egypt_court', '애굽 궁정(전승)', '모세가 바로 앞에 선 궁정 (출 5-12장). 열 재앙의 무대.', '👑', null, 30.05, 31.25, null, 'palace', (select id from landmarks where code = 'rgn_egypt'), null, 50, '{"era_exodus"}'::text[], '{}'::text[]),
  ('lm_exo_giza_pyramid', '기자 피라미드', '이집트 고대 피라미드. 출애굽 시대 이미 천 년 이상 된 거대 무덤.', '🔺', null, 29.98, 31.13, null, 'city', (select id from landmarks where code = 'rgn_egypt'), null, 70, '{"era_exodus"}'::text[], '{}'::text[]),
  ('lm_exo_goshen', '애굽(고센 일대, 전승)', '이스라엘이 노예 생활을 한 애굽 동북부 (출 1장). 출애굽의 출발점.', '🌾', null, 30.78, 31.36, null, 'city', (select id from landmarks where code = 'rgn_egypt'), null, 50, '{"era_exodus"}'::text[], '{}'::text[]),
  ('lm_exo_kadesh_barnea', '가데스 바네아', '광야 38년 본거지. 정탐꾼을 보낸 곳 (민 13장).', '⛺', null, 30.6786, 34.4325, null, 'campsite', (select id from landmarks where code = 'rgn_negev'), null, 80, '{"era_exodus"}'::text[], '{}'::text[]),
  ('lm_exo_marah', '마라(전승)', '쓴 물이 단 물로 변한 광야 첫 정착지 (출 15:22-25).', '💧', null, 29.85, 32.95, null, 'campsite', (select id from landmarks where code = 'rgn_sinai_peninsula'), null, 50, '{"era_exodus"}'::text[], '{}'::text[]),
  ('lm_exo_midian_desert', '애굽 → 미디안(전승)', '모세가 살인 후 도망친 광야 (출 2:15). 양치다 떨기나무 부르심을 받음.', '🏜️', null, 28.4, 35.7, null, 'wilderness', (select id from landmarks where code = 'rgn_sinai_peninsula'), null, 50, '{"era_exodus"}'::text[], '{}'::text[]),
